SELECT DISTINCT ' ' AS 'EXISTING LOGIC DETAIL MEMBER LISTING'
,mpa.ProviderID
,prov.NPI
,prov.fullname AS [ECM Provider]
,pof.memid
,pof.carriermemid
,pof.lastname
,pof.firstname
,pof.TargetPopulation
,pof.[RANGE NOTE(s)]
FROM INFORMATICS.dbo.ECMPOF_CHILD_MHSMISUD AS pof -- EXISTING LOGIC
	INNER JOIN ProviderPortal.ECM.Member AS m ON pof.memid = m.MemberId
		LEFT JOIN [ProviderPortal].[ECM].[MemberProviderAssigment]  AS mpa ON pof.memid = mpa.MemberId
		LEFT JOIN HMOPROD_PLANDATA.dbo.[provider]  AS prov ON mpa.ProviderID = prov.provid
WHERE 1=1
	AND pof.[RunDate] = ( SELECT MAX( i.[RunDate] ) FROM INFORMATICS.dbo.ECMPOF_CHILD_MHSMISUD AS i WITH (NOLOCK) )
	AND m.ISECM = 1
	AND m.EnrollmentStatus = 'Assigned'

SELECT ' ' AS 'EXISTING LOGIC Unique Member Count by ECM Provider'
,pof.TargetPopulation
,mpa.ProviderID
,prov.NPI
,prov.fullname AS [ECM Provider]
,COUNT(DISTINCT(pof.memid)) AS [Unique Member Count]
FROM INFORMATICS.dbo.ECMPOF_CHILD_MHSMISUD AS pof -- EXISTING LOGIC
	INNER JOIN ProviderPortal.ECM.Member AS m ON pof.memid = m.MemberId
		LEFT JOIN [ProviderPortal].[ECM].[MemberProviderAssigment]  AS mpa ON pof.memid = mpa.MemberId
		LEFT JOIN HMOPROD_PLANDATA.dbo.[provider]  AS prov ON mpa.ProviderID = prov.provid
WHERE 1=1
	AND pof.[RunDate] = ( SELECT MAX( i.[RunDate] ) FROM INFORMATICS.dbo.ECMPOF_CHILD_MHSMISUD AS i WITH (NOLOCK) )
	AND m.ISECM = 1
	AND m.EnrollmentStatus = 'Assigned'
GROUP BY pof.TargetPopulation,mpa.ProviderID,prov.NPI,prov.fullname

