-- =====================================================================
	-- POF ECM PROVIDER 20260714 -- REBUILT per JAG spec --
	-- Sir Allan Sombillo / Sir Yousaf Farook, on behalf of JAG, do NOT want memberattribute used --
	-- Qualifying gate IS ProviderPortal.ECM.Member directly (m.ISECM = 1 AND
	-- m.EnrollmentStatus = 'Assigned'), joined ON pof.memid = m.MemberId, matching the CODE Malik
	-- supplied 20260714 exactly. The prior #ECMEnrolled# memberattribute derivation has been removed --
	-- SCOPE 20260714: CHILD_MHSMISUD only, built AS the confirmed template. Malik IS gathering the
	-- common field list needed to safely UNION the remaining 16 POF tables' detail listings (pof.*
	-- varies by table, e.g. code/code descr/code type columns look diagnosis-driven-POF-specific).
	-- The COUNTS BY PROVIDER script (EXISTING POF v ALGORITHM POF ECM COUNTS 20260714.sql) already
	-- covers all 17 existing / 16 algorithm POF tables safely, since it only needs memid AND
	-- TargetPopulation, confirmed common across every branch. ONLY the detail LISTING (pof.*) IS
	-- paused pending that field list. Repeat this exact template per table, one block per POF
	-- category, once the field list IS confirmed --
-- =====================================================================

-- =====================================================================
	-- CHILD SMH or SUD -- EXISTING LOGIC --
-- =====================================================================
SELECT ' ' AS 'EXISTING LOGIC DETAIL MEMBER LISTING'
,mpa.ProviderID
,prov.NPI
,prov.fullname AS [ECM Provider]
,pof.*
FROM INFORMATICS.dbo.ECMPOF_CHILD_MHSMISUD (NOLOCK) AS pof -- EXISTING LOGIC
	INNER JOIN ProviderPortal.ECM.Member (NOLOCK) AS m ON pof.memid = m.MemberId
	LEFT JOIN [ProviderPortal].[ECM].[MemberProviderAssigment] (NOLOCK) AS mpa ON pof.memid = mpa.MemberId
		LEFT JOIN HMOPROD_PLANDATA.dbo.[provider] (NOLOCK) AS prov ON mpa.ProviderID = prov.provid
WHERE 1=1
	AND pof.[RunDate] = ( SELECT MAX(i.[RunDate]) FROM INFORMATICS.dbo.ECMPOF_CHILD_MHSMISUD AS i WITH (NOLOCK) )
	AND m.ISECM = 1
	AND m.EnrollmentStatus = 'Assigned'

SELECT ' ' AS 'EXISTING LOGIC Unique Member Count by ECM Provider'
,pof.TargetPopulation
,mpa.ProviderID
,prov.NPI
,prov.fullname AS [ECM Provider]
,COUNT(DISTINCT(pof.memid)) AS [Unique Member Count]
FROM INFORMATICS.dbo.ECMPOF_CHILD_MHSMISUD (NOLOCK) AS pof -- EXISTING LOGIC
	INNER JOIN ProviderPortal.ECM.Member (NOLOCK) AS m ON pof.memid = m.MemberId
	LEFT JOIN [ProviderPortal].[ECM].[MemberProviderAssigment] (NOLOCK) AS mpa ON pof.memid = mpa.MemberId
		LEFT JOIN HMOPROD_PLANDATA.dbo.[provider] (NOLOCK) AS prov ON mpa.ProviderID = prov.provid
WHERE 1=1
	AND pof.[RunDate] = ( SELECT MAX(i.[RunDate]) FROM INFORMATICS.dbo.ECMPOF_CHILD_MHSMISUD AS i WITH (NOLOCK) )
	AND m.ISECM = 1
	AND m.EnrollmentStatus = 'Assigned'
GROUP BY pof.TargetPopulation
,mpa.ProviderID
,prov.NPI
,prov.fullname

